 83	func findDefinitionByID(defs []Definition, definitionID string) (Definition, error) {
 84		var (
 85			best  Definition
 86			found bool
 87		)
 88		for _, def := range defs {
 89			if def.ID != definitionID {
 90				continue
 91			}
 92			if !found || def.CreatedAt.After(best.CreatedAt) || (def.CreatedAt.Equal(best.CreatedAt) && def.ID > best.ID) {
 93				best = def
 94				found = true
 95			}
 96		}
 97		if !found {
 98			return Definition{}, fmt.Errorf("exec definition for %q not found", definitionID)
 99		}
100		if best.ID == "" {
101			return Definition{}, fmt.Errorf("exec definition for %q is missing id", definitionID)
102		}
103		return best, nil
104	}
